using System.Windows;
using System.Windows.Media;
using System.Windows.Media.Imaging;

namespace Login;

public partial class Painel : Window
{
    public string nomeUsuario;
    public Painel()
    {
        InitializeComponent();
    }

    private void BotaoBuscarImagem(object sender, RoutedEventArgs e)
    {
        string nomeEstudante = tbEstudanteNome.Text;
        
        //Estrutura Switch-case
        switch (nomeEstudante.ToLower())
        {
            case "rebeca spinola":
                imagemAluna.Source =
                    CriarImagem(
                        "https://ichef.bbci.co.uk/ace/ws/640/cpsprodpb/11F73/production/_120878537_4cfca0d7-2b27-474f-93b7-4c31269c5cdf.jpg.webp");
                break;
            case "sarah":
                imagemAluna.Source = CriarImagem(
                    "data:image/jpeg;base64,");
                break;
            case "yatra":
                imagemAluna.Source =
                    CriarImagem(
                        "https://blog-static.petlove.com.br/wp-content/uploads/2021/08/Gato-laranja-filhote.jpg");
                break;
            case "maria":
                imagemAluna.Source = CriarImagem(
                    "data:image/jpeg;base64,");
                break;
            case "laura":
                imagemAluna.Source = CriarImagem(
                    "data:image/jpeg;base64,");
                break;
            case "isabela":
                imagemAluna.Source = CriarImagem(
                    "data:image/jpeg;base64,");
                break;
            case "rebecca dias":
                imagemAluna.Source = CriarImagem(
                    "data:image/jpeg;base64,");
                break;
            case "joice":
                imagemAluna.Source = CriarImagem("pack://application:,,,/Imagem");
                break;
            case "adrielly":
                imagemAluna.Source =
                    CriarImagem("pack://application:,,,/Images/");
                break;
            default:
                imagemAluna.Source = CriarImagem("pack://application:,,,/Images/padrao.jpg");
                break;
        }
    }

    private static BitmapImage CriarImagem(string url)
    {
        var imageBitmap = new BitmapImage();
        imageBitmap.BeginInit();
        imageBitmap.UriSource =
            new Uri(url);
        imageBitmap.EndInit();
        return imageBitmap;
    }
}